ADMIN_HTML = '<!DOCTYPE html>\n<html lang="en" data-theme="light">\n<head>\n<meta charset="utf-8">\n<meta name="viewport" content="width=device-width, initial-scale=1">\n<title>asr2clip — Admin Panel</title>\n<style>\n*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}\n\n/* ===== Theme Variables ===== */\n[data-theme="light"]{\n  --bg:#f5f6fa;--surface:#ffffff;--border:#e2e4ea;\n  --text:#1a1d2e;--muted:#6b7085;--accent:#4f6ef7;--accent-hover:#3b5ae0;\n  --green:#22c55e;--yellow:#eab308;--red:#ef4444;\n  --shadow:0 1px 3px rgba(0,0,0,.08);\n  --card-shadow:0 1px 4px rgba(0,0,0,.05);\n  --input-bg:#f8f9fb;--input-border:#d1d5de;\n  --tab-bg:#eceef3;--tab-active-bg:#ffffff;\n  --toggle-bg:#e2e4ea;--toggle-hover:#d1d5de;\n}\n[data-theme="dark"]{\n  --bg:#13151c;--surface:#1c1f2b;--border:#2a2e3d;\n  --text:#e0e2ea;--muted:#8b8fa8;--accent:#6c8cff;--accent-hover:#8aa4ff;\n  --green:#4ade80;--yellow:#facc15;--red:#f87171;\n  --shadow:0 1px 3px rgba(0,0,0,.3);\n  --card-shadow:0 1px 4px rgba(0,0,0,.2);\n  --input-bg:#242736;--input-border:#363a4d;\n  --tab-bg:#1c1f2b;--tab-active-bg:#242736;\n  --toggle-bg:#2a2e3d;--toggle-hover:#363a4d;\n}\n\n/* ===== Base ===== */\nbody{background:var(--bg);color:var(--text);font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif;line-height:1.6;min-height:100vh;transition:background .2s,color .2s}\na{color:var(--accent);text-decoration:none}\nbutton{cursor:pointer;font-family:inherit}\n\n/* ===== Header ===== */\n.header{display:flex;align-items:center;justify-content:space-between;padding:16px 28px;border-bottom:1px solid var(--border);background:var(--surface)}\n.header-left{display:flex;align-items:center;gap:10px}\n.logo{display:flex;align-items:center;gap:8px}\n.logo svg{width:28px;height:24px}\n.logo h1{font-size:1.2rem;font-weight:600}\n.badge{background:var(--accent);color:#fff;font-size:.65rem;padding:2px 8px;border-radius:10px;font-weight:500;letter-spacing:.02em}\n.header-right{display:flex;align-items:center;gap:8px}\n.icon-btn{display:flex;align-items:center;justify-content:center;width:36px;height:36px;border-radius:8px;border:1px solid var(--border);background:var(--toggle-bg);color:var(--text);transition:background .15s}\n.icon-btn:hover{background:var(--toggle-hover)}\n.icon-btn svg{width:18px;height:18px}\n.lang-btn{width:auto;padding:0 10px;font-size:.78rem;font-weight:500;gap:4px}\n\n/* ===== Tab Bar ===== */\n.tab-bar{display:flex;gap:0;padding:0 28px;background:var(--surface);border-bottom:1px solid var(--border)}\n.tab-btn{padding:12px 20px;font-size:.85rem;font-weight:500;color:var(--muted);background:none;border:none;border-bottom:2px solid transparent;transition:color .15s,border-color .15s;display:flex;align-items:center;gap:6px}\n.tab-btn:hover{color:var(--text)}\n.tab-btn.active{color:var(--accent);border-bottom-color:var(--accent)}\n.tab-btn svg{width:16px;height:16px}\n\n/* ===== Main Content ===== */\n.container{max-width:1400px;margin:0 auto;padding:24px 28px}\n.tab-panel{display:none}\n.tab-panel.active{display:block}\n\n/* ===== Cards ===== */\n.card{background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:20px 24px;box-shadow:var(--card-shadow);transition:background .2s,border-color .2s}\n.card+.card{margin-top:16px}\n.card-title{font-size:.8rem;font-weight:600;text-transform:uppercase;letter-spacing:.05em;color:var(--muted);margin-bottom:12px}\n\n/* ===== Placeholder ===== */\n.placeholder{text-align:center;padding:60px 20px;color:var(--muted);font-size:.95rem}\n\n/* ===== Dashboard ===== */\n.dash-grid{display:flex;flex-direction:column;gap:16px}\n\n/* Status bar — compact horizontal strip */\n.status-row{display:flex;flex-wrap:wrap;gap:8px 20px;font-size:.88rem;align-items:center}\n.status-item{display:flex;align-items:center;gap:6px}\n.status-item .label{color:var(--muted)}\n.status-item .value{font-weight:500}\n.status-dot{width:8px;height:8px;border-radius:50%;display:inline-block;flex-shrink:0}\n.status-dot.ok{background:var(--green)}\n.status-dot.err{background:var(--red)}\n\n/* Stat number */\n.stat-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}\n@media(max-width:640px){.stat-grid{grid-template-columns:1fr}}\n.stat-box{text-align:center;padding:16px 8px;border-radius:8px;background:var(--input-bg)}\n.stat-num{font-size:1.8rem;font-weight:700;line-height:1.2}\n.stat-num.green{color:var(--green)}\n.stat-num.yellow{color:var(--yellow)}\n.stat-num.red{color:var(--red)}\n.stat-label{font-size:.72rem;color:var(--muted);text-transform:uppercase;letter-spacing:.04em;margin-top:4px}\n\n/* Last transcription */\n.last-text-box{background:var(--input-bg);border:1px solid var(--input-border);border-radius:8px;padding:14px 16px;font-size:.9rem;min-height:56px;color:var(--text);line-height:1.5;word-break:break-word}\n.last-text-box.empty{color:var(--muted);font-style:italic}\n.last-meta{font-size:.72rem;color:var(--muted);margin-top:8px}\n\n/* ===== Config Form ===== */\n.form-group{margin-bottom:16px}\n.form-label{display:block;font-size:.82rem;font-weight:500;color:var(--muted);margin-bottom:5px}\n.form-hint{font-size:.75rem;color:var(--muted);opacity:.75;margin-top:4px}\n.form-input{width:100%;padding:9px 12px;font-size:.88rem;font-family:inherit;color:var(--text);background:var(--input-bg);border:1px solid var(--input-border);border-radius:8px;outline:none;transition:border-color .15s}\n.form-input:focus{border-color:var(--accent)}\n.input-wrap{position:relative}\n.input-wrap .form-input{padding-right:40px}\n.input-wrap .eye-btn{position:absolute;right:8px;top:50%;transform:translateY(-50%);background:none;border:none;color:var(--muted);padding:4px;cursor:pointer}\n.input-wrap .eye-btn:hover{color:var(--text)}\n.input-wrap .eye-btn svg{width:16px;height:16px}\n\n/* Toggle switch */\n.toggle-row{display:flex;align-items:center;justify-content:space-between}\n.toggle-switch{position:relative;width:44px;height:24px;flex-shrink:0}\n.toggle-switch input{opacity:0;width:0;height:0}\n.toggle-slider{position:absolute;inset:0;background:var(--input-border);border-radius:12px;cursor:pointer;transition:background .2s}\n.toggle-slider::before{content:"";position:absolute;width:18px;height:18px;left:3px;bottom:3px;background:#fff;border-radius:50%;transition:transform .2s}\n.toggle-switch input:checked+.toggle-slider{background:var(--accent)}\n.toggle-switch input:checked+.toggle-slider::before{transform:translateX(20px)}\n\n/* Buttons */\n.btn{display:inline-flex;align-items:center;gap:6px;padding:9px 20px;font-size:.85rem;font-weight:500;border:none;border-radius:6px;cursor:pointer;transition:background .15s}\n.btn-primary{background:var(--accent);color:#fff}\n.btn-primary:hover{background:var(--accent-hover)}\n.btn-primary:disabled{opacity:.5;cursor:not-allowed}\n.btn-restart{background:var(--toggle-bg);color:var(--text);border:1px solid var(--border)}\n.btn-restart:hover{background:var(--toggle-hover)}\n.btn-restart:disabled{opacity:.5;cursor:not-allowed}\n.form-actions{margin-top:20px;display:flex;gap:10px;align-items:center;flex-wrap:wrap}\n\n/* Section label */\n.section-label{font-size:.72rem;font-weight:600;text-transform:uppercase;letter-spacing:.05em;color:var(--accent);border-bottom:1px solid var(--border);padding-bottom:6px;margin:16px 0 12px}\n\n/* Engine warning */\n.engine-warn{display:flex;align-items:center;gap:6px;margin-top:12px;padding:8px 12px;border-radius:8px;font-size:.82rem;color:var(--yellow);background:color-mix(in srgb, var(--yellow) 8%, var(--surface));border:1px solid color-mix(in srgb, var(--yellow) 20%, var(--border))}\n.engine-warn svg{flex-shrink:0;color:var(--yellow)}\n\n/* Select styling */\nselect.form-input{appearance:auto;cursor:pointer}\n\n/* Toast */\n.toast{position:fixed;bottom:24px;right:24px;padding:12px 20px;border-radius:10px;font-size:.85rem;color:#fff;z-index:999;opacity:0;transform:translateY(10px);transition:opacity .2s,transform .2s;pointer-events:none}\n.toast.show{opacity:1;transform:translateY(0)}\n.toast.success{background:var(--green)}\n.toast.error{background:var(--red)}\n\n/* ===== Device List ===== */\n.device-list{list-style:none;padding:0}\n.device-item{display:flex;align-items:center;justify-content:space-between;padding:12px 16px;border:1px solid var(--border);border-radius:8px;margin-bottom:8px;transition:background .15s,border-color .15s}\n.device-item.active{border-color:var(--accent);background:color-mix(in srgb, var(--accent) 6%, var(--surface))}\n.device-info{flex:1;min-width:0}\n.device-name{font-size:.9rem;font-weight:500;display:flex;align-items:center;gap:6px}\n.device-name .idx{color:var(--muted);font-size:.78rem;font-weight:400}\n.device-detail{font-size:.75rem;color:var(--muted);margin-top:2px}\n.device-badges{display:flex;gap:4px;margin-left:8px;flex-shrink:0}\n.device-badge{font-size:.65rem;padding:2px 7px;border-radius:6px;font-weight:500}\n.device-badge.default{background:color-mix(in srgb, var(--green) 15%, var(--surface));color:var(--green)}\n.device-badge.current{background:color-mix(in srgb, var(--accent) 15%, var(--surface));color:var(--accent)}\n.btn-sm{padding:5px 12px;font-size:.78rem;border-radius:6px}\n.device-empty{text-align:center;padding:40px 20px;color:var(--muted);font-size:.9rem}\n\n/* ===== Two-column Dashboard Grid ===== */\n.dash-two-col{display:grid;grid-template-columns:1fr 1fr;gap:16px}\n.dash-col{display:flex;flex-direction:column;gap:16px}\n.dash-col .card{margin-top:0}\n@media(max-width:960px){.dash-two-col{grid-template-columns:1fr}}\n\n/* ===== History List ===== */\n.history-list{max-height:400px;overflow-y:auto;margin-top:8px}\n.history-item{padding:10px 12px;border-bottom:1px solid var(--border);font-size:.85rem;line-height:1.4}\n.history-item:last-child{border-bottom:none}\n.history-text{color:var(--text);word-break:break-word}\n.history-meta{font-size:.72rem;color:var(--muted);margin-top:3px;display:flex;gap:10px}\n.history-empty{text-align:center;padding:32px 16px;color:var(--muted);font-size:.88rem}\n\n/* ===== Test Record ===== */\n.test-row{display:flex;align-items:center;gap:10px;margin-top:8px;flex-wrap:wrap}\n.test-dur{width:64px;padding:7px 10px;font-size:.85rem;text-align:center}\n.test-result{margin-top:12px;padding:10px 14px;background:var(--input-bg);border:1px solid var(--input-border);border-radius:6px;font-size:.88rem;word-break:break-word;display:none}\n.test-result.visible{display:block}\n</style>\n</head>\n<body>\n\n<!-- Header -->\n<header class="header">\n  <div class="header-left">\n    <div class="logo">\n      <svg viewBox="0 0 120 110" xmlns="http://www.w3.org/2000/svg" fill="none">\n        <defs><linearGradient id="logo-g" x1="0" y1="0" x2="120" y2="110" gradientUnits="userSpaceOnUse"><stop stop-color="#4f46e5"/><stop offset="1" stop-color="#7c3aed"/></linearGradient></defs>\n        <rect x="8" y="44" width="7" height="22" rx="3.5" fill="url(#logo-g)" opacity="0.6"/>\n        <rect x="20" y="32" width="7" height="46" rx="3.5" fill="url(#logo-g)" opacity="0.75"/>\n        <rect x="32" y="38" width="7" height="34" rx="3.5" fill="url(#logo-g)" opacity="0.9"/>\n        <rect x="44" y="26" width="7" height="58" rx="3.5" fill="url(#logo-g)"/>\n        <rect x="56" y="42" width="7" height="26" rx="3.5" fill="url(#logo-g)" opacity="0.7"/>\n        <path d="M70 55 L80 55" stroke="url(#logo-g)" stroke-width="2.5" stroke-linecap="round" opacity="0.45"/>\n        <path d="M77 50 L83 55 L77 60" fill="none" stroke="url(#logo-g)" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" opacity="0.45"/>\n        <rect x="88" y="28" width="28" height="54" rx="5" stroke="url(#logo-g)" stroke-width="3.5"/>\n        <line x1="95" y1="42" x2="109" y2="42" stroke="url(#logo-g)" stroke-width="2.5" stroke-linecap="round" opacity="0.55"/>\n        <line x1="95" y1="50" x2="106" y2="50" stroke="url(#logo-g)" stroke-width="2.5" stroke-linecap="round" opacity="0.55"/>\n        <line x1="95" y1="58" x2="109" y2="58" stroke="url(#logo-g)" stroke-width="2.5" stroke-linecap="round" opacity="0.55"/>\n        <line x1="95" y1="66" x2="103" y2="66" stroke="url(#logo-g)" stroke-width="2.5" stroke-linecap="round" opacity="0.55"/>\n      </svg>\n      <h1>asr2clip</h1>\n    </div>\n    <span class="badge" id="version-badge">v-.-.-</span>\n  </div>\n  <div class="header-right">\n    <button class="icon-btn" id="theme-toggle" title="Toggle theme">\n      <svg id="icon-sun" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">\n        <circle cx="12" cy="12" r="5"/><line x1="12" y1="1" x2="12" y2="3"/><line x1="12" y1="21" x2="12" y2="23"/><line x1="4.22" y1="4.22" x2="5.64" y2="5.64"/><line x1="18.36" y1="18.36" x2="19.78" y2="19.78"/><line x1="1" y1="12" x2="3" y2="12"/><line x1="21" y1="12" x2="23" y2="12"/><line x1="4.22" y1="19.78" x2="5.64" y2="18.36"/><line x1="18.36" y1="5.64" x2="19.78" y2="4.22"/>\n      </svg>\n      <svg id="icon-moon" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="display:none">\n        <path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"/>\n      </svg>\n    </button>\n    <button class="icon-btn lang-btn" id="lang-toggle">EN</button>\n  </div>\n</header>\n\n<!-- Tab Bar -->\n<nav class="tab-bar">\n  <button class="tab-btn active" data-tab="dashboard">\n    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/></svg>\n    <span data-i18n="tab_dashboard">Dashboard</span>\n  </button>\n  <button class="tab-btn" data-tab="config">\n    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg>\n    <span data-i18n="tab_config">Configuration</span>\n  </button>\n  <button class="tab-btn" data-tab="devices">\n    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/></svg>\n    <span data-i18n="tab_devices">Devices</span>\n  </button>\n</nav>\n\n<!-- Tab Panels -->\n<main class="container">\n  <div id="panel-dashboard" class="tab-panel active">\n    <div class="dash-grid">\n      <!-- Status Bar — full width -->\n      <div class="card">\n        <div class="status-row">\n          <div class="status-item"><span class="status-dot ok" id="status-dot"></span><span class="value" id="status-mode">--</span></div>\n          <div class="status-item"><span class="label">PID:</span><span class="value" id="status-pid">--</span></div>\n          <div class="status-item"><span class="label" data-i18n="lbl_uptime">Uptime:</span><span class="value" id="status-uptime">--</span></div>\n          <div class="status-item"><span class="label" data-i18n="lbl_device">Device:</span><span class="value" id="status-device">--</span></div>\n        </div>\n      </div>\n      <!-- Two-column grid -->\n      <div class="dash-two-col">\n        <!-- Left column: Stats + Last Transcription -->\n        <div class="dash-col">\n          <div class="card">\n            <div class="card-title" data-i18n="card_stats">Statistics</div>\n            <div class="stat-grid">\n              <div class="stat-box"><div class="stat-num green" id="stat-count">0</div><div class="stat-label" data-i18n="stat_transcriptions">Transcriptions</div></div>\n              <div class="stat-box"><div class="stat-num yellow" id="stat-duration">0s</div><div class="stat-label" data-i18n="stat_duration">Total Duration</div></div>\n              <div class="stat-box"><div class="stat-num red" id="stat-errors">0</div><div class="stat-label" data-i18n="stat_errors">Errors</div></div>\n            </div>\n          </div>\n          <div class="card">\n            <div class="card-title" data-i18n="card_last_text">Last Transcription</div>\n            <div class="last-text-box empty" id="last-text" data-i18n="no_transcription">No transcription yet</div>\n            <div class="last-meta" id="last-meta"></div>\n          </div>\n        </div>\n        <!-- Right column: History + Test Record -->\n        <div class="dash-col">\n          <div class="card">\n            <div class="card-title" data-i18n="card_history">Transcription History</div>\n            <div class="history-list" id="history-list">\n              <div class="history-empty" data-i18n="no_history">No history yet</div>\n            </div>\n          </div>\n          <div class="card">\n            <div class="card-title" data-i18n="card_test">Test Record</div>\n            <div class="test-row">\n              <button class="btn btn-primary" id="btn-test-record" data-i18n="btn_record">Record</button>\n              <label style="font-size:.82rem;color:var(--muted);display:flex;align-items:center;gap:5px">\n                <span data-i18n="lbl_duration_sec">Duration (sec)</span>\n                <input class="form-input test-dur" id="test-duration" type="number" min="1" max="10" value="3">\n              </label>\n            </div>\n            <div class="test-result" id="test-result"></div>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n  <div id="panel-config" class="tab-panel">\n    <div class="card">\n      <div class="card-title" data-i18n="card_config">Configuration</div>\n      <!-- Engine selector -->\n      <div class="form-group">\n        <label class="form-label" data-i18n="lbl_engine">Engine</label>\n        <select class="form-input" id="cfg-engine">\n          <option value="openai_compat">OpenAI Compatible</option>\n          <option value="sherpa_onnx">Sherpa ONNX (Local)</option>\n        </select>\n      </div>\n      <!-- OpenAI fields -->\n      <div id="fields-openai">\n        <div class="section-label" data-i18n="engine_openai">OpenAI Compatible</div>\n        <div class="form-group">\n          <label class="form-label" data-i18n="lbl_api_url">API Base URL</label>\n          <input class="form-input" id="cfg-api-url" type="text" placeholder="https://api.openai.com/v1/">\n        </div>\n        <div class="form-group">\n          <label class="form-label" data-i18n="lbl_model">Model Name</label>\n          <input class="form-input" id="cfg-model" type="text" placeholder="whisper-1">\n        </div>\n        <div class="form-group">\n          <label class="form-label" data-i18n="lbl_api_key">API Key</label>\n          <div class="input-wrap">\n            <input class="form-input" id="cfg-api-key" type="password" placeholder="sk-...">\n            <button class="eye-btn" id="toggle-key-vis" type="button" title="Show/hide">\n              <svg id="eye-open" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>\n              <svg id="eye-closed" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="display:none"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94"/><path d="M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19"/><line x1="1" y1="1" x2="23" y2="23"/></svg>\n            </button>\n          </div>\n        </div>\n      </div>\n      <!-- Sherpa ONNX fields -->\n      <div id="fields-sherpa" style="display:none">\n        <div class="section-label" data-i18n="engine_sherpa">Sherpa ONNX (Local)</div>\n        <div class="form-group">\n          <label class="form-label" data-i18n="lbl_model">Model Name</label>\n          <input class="form-input" id="cfg-sherpa-model" type="text" list="sherpa-models-list" placeholder="sensevoice-small">\n          <datalist id="sherpa-models-list"></datalist>\n          <div class="form-hint model-warn" id="model-warn" style="display:none;color:var(--yellow)" data-i18n="model_not_available">Model not downloaded. Run: asr2clip --download-model</div>\n        </div>\n        <div class="form-group">\n          <label class="form-label" data-i18n="lbl_model_dir">Model Directory</label>\n          <input class="form-input" id="cfg-model-dir" type="text" placeholder="~/.cache/sherpa-onnx">\n        </div>\n        <div class="form-group">\n          <label class="form-label" data-i18n="lbl_threads">Threads</label>\n          <input class="form-input" id="cfg-threads" type="number" min="1" max="32" value="4">\n        </div>\n      </div>\n      <!-- General -->\n      <div class="section-label" data-i18n="section_general">General</div>\n      <div class="form-group">\n        <div class="toggle-row">\n          <label class="form-label" style="margin-bottom:0" data-i18n="lbl_quiet">Quiet Mode</label>\n          <label class="toggle-switch"><input type="checkbox" id="cfg-quiet"><span class="toggle-slider"></span></label>\n        </div>\n        <div class="form-hint" data-i18n="hint_quiet">Only output transcriptions and errors, suppress all other messages</div>\n      </div>\n      <div class="form-actions">\n        <button class="btn btn-primary" id="btn-save-config" data-i18n="btn_save">Save</button>\n        <button class="btn btn-restart" id="btn-restart-engine" data-i18n="btn_restart">Restart Engine</button>\n        <span id="save-status" style="font-size:.82rem;color:var(--muted)"></span>\n      </div>\n      <div id="engine-warn" class="engine-warn" style="display:none">\n        <svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>\n        <span data-i18n="engine_restart_warn">Engine changed — click "Restart Engine" to apply</span>\n      </div>\n    </div>\n  </div>\n  <div id="panel-devices" class="tab-panel">\n    <div class="card">\n      <div class="card-title" data-i18n="card_devices">Audio Input Devices</div>\n      <div id="device-list" class="device-list">\n        <div class="device-empty" data-i18n="loading">Loading...</div>\n      </div>\n    </div>\n  </div>\n</main>\n\n<script>\n// ===== i18n =====\nconst I18N = {\n  en: {\n    tab_dashboard: "Dashboard",\n    tab_config: "Configuration",\n    tab_devices: "Devices",\n    card_status: "Status",\n    card_stats: "Statistics",\n    card_last_text: "Last Transcription",\n    lbl_uptime: "Uptime:",\n    lbl_device: "Device:",\n    stat_transcriptions: "Transcriptions",\n    stat_duration: "Total Duration",\n    stat_errors: "Errors",\n    no_transcription: "No transcription yet",\n    card_config: "Configuration",\n    lbl_engine: "Engine",\n    engine_openai: "OpenAI Compatible",\n    engine_sherpa: "Sherpa ONNX (Local)",\n    section_general: "General",\n    lbl_api_url: "API Base URL",\n    lbl_model: "Model Name",\n    lbl_api_key: "API Key",\n    lbl_model_dir: "Model Directory",\n    lbl_threads: "Threads",\n    lbl_quiet: "Quiet Mode",\n    hint_quiet: "Only output transcriptions and errors, suppress all other messages",\n    btn_save: "Save",\n    save_ok: "Configuration saved",\n    save_fail: "Failed to save",\n    btn_restart: "Restart Engine",\n    engine_restart_warn: "Engine changed \\u2014 click \\"Restart Engine\\" to apply",\n    restart_ok: "Engine restarted",\n    restart_fail: "Failed to restart engine",\n    restarting: "Restarting...",\n    card_devices: "Audio Input Devices",\n    loading: "Loading...",\n    badge_default: "Default",\n    badge_active: "Active",\n    btn_activate: "Set Active",\n    no_devices: "No audio input devices found",\n    device_set_ok: "Device activated",\n    device_set_fail: "Failed to set device",\n    lbl_channels: "ch",\n    lbl_hz: "Hz",\n    card_history: "Transcription History",\n    no_history: "No history yet",\n    card_test: "Test Record",\n    btn_record: "Record",\n    recording: "Recording...",\n    lbl_duration_sec: "Duration (sec)",\n    test_ok: "Test transcription complete",\n    test_fail: "Test recording failed",\n    model_not_available: "Model not downloaded. Run: asr2clip --download-model",\n  },\n  zh: {\n    tab_dashboard: "\\u4eea\\u8868\\u76d8",\n    tab_config: "\\u914d\\u7f6e",\n    tab_devices: "\\u8bbe\\u5907",\n    card_status: "\\u72b6\\u6001",\n    card_stats: "\\u7edf\\u8ba1",\n    card_last_text: "\\u6700\\u8fd1\\u8f6c\\u5f55",\n    lbl_uptime: "\\u8fd0\\u884c\\u65f6\\u95f4:",\n    lbl_device: "\\u8bbe\\u5907:",\n    stat_transcriptions: "\\u8f6c\\u5f55\\u6b21\\u6570",\n    stat_duration: "\\u603b\\u65f6\\u957f",\n    stat_errors: "\\u9519\\u8bef",\n    no_transcription: "\\u6682\\u65e0\\u8f6c\\u5f55",\n    card_config: "\\u914d\\u7f6e",\n    lbl_engine: "\\u5f15\\u64ce",\n    engine_openai: "OpenAI \\u517c\\u5bb9",\n    engine_sherpa: "Sherpa ONNX (\\u672c\\u5730)",\n    section_general: "\\u901a\\u7528",\n    lbl_api_url: "API \\u57fa\\u7840 URL",\n    lbl_model: "\\u6a21\\u578b\\u540d\\u79f0",\n    lbl_api_key: "API \\u5bc6\\u94a5",\n    lbl_model_dir: "\\u6a21\\u578b\\u76ee\\u5f55",\n    lbl_threads: "\\u7ebf\\u7a0b\\u6570",\n    lbl_quiet: "\\u9759\\u97f3\\u6a21\\u5f0f",\n    hint_quiet: "\\u4ec5\\u8f93\\u51fa\\u8f6c\\u5f55\\u7ed3\\u679c\\u548c\\u9519\\u8bef\\u4fe1\\u606f\\uff0c\\u9690\\u85cf\\u5176\\u4ed6\\u6240\\u6709\\u6d88\\u606f",\n    btn_save: "\\u4fdd\\u5b58",\n    save_ok: "\\u914d\\u7f6e\\u5df2\\u4fdd\\u5b58",\n    save_fail: "\\u4fdd\\u5b58\\u5931\\u8d25",\n    btn_restart: "\\u91cd\\u542f\\u5f15\\u64ce",\n    engine_restart_warn: "\\u5f15\\u64ce\\u5df2\\u66f4\\u6539 \\u2014 \\u8bf7\\u70b9\\u51fb\\u201c\\u91cd\\u542f\\u5f15\\u64ce\\u201d\\u4ee5\\u5e94\\u7528",\n    restart_ok: "\\u5f15\\u64ce\\u5df2\\u91cd\\u542f",\n    restart_fail: "\\u91cd\\u542f\\u5f15\\u64ce\\u5931\\u8d25",\n    restarting: "\\u91cd\\u542f\\u4e2d...",\n    card_devices: "\\u97f3\\u9891\\u8f93\\u5165\\u8bbe\\u5907",\n    loading: "\\u52a0\\u8f7d\\u4e2d...",\n    badge_default: "\\u9ed8\\u8ba4",\n    badge_active: "\\u5f53\\u524d",\n    btn_activate: "\\u8bbe\\u4e3a\\u6d3b\\u52a8",\n    no_devices: "\\u672a\\u627e\\u5230\\u97f3\\u9891\\u8f93\\u5165\\u8bbe\\u5907",\n    device_set_ok: "\\u8bbe\\u5907\\u5df2\\u6fc0\\u6d3b",\n    device_set_fail: "\\u8bbe\\u7f6e\\u8bbe\\u5907\\u5931\\u8d25",\n    lbl_channels: "\\u58f0\\u9053",\n    lbl_hz: "Hz",\n    card_history: "\\u8f6c\\u5f55\\u5386\\u53f2",\n    no_history: "\\u6682\\u65e0\\u5386\\u53f2\\u8bb0\\u5f55",\n    card_test: "\\u5f55\\u97f3\\u6d4b\\u8bd5",\n    btn_record: "\\u5f55\\u5236",\n    recording: "\\u5f55\\u5236\\u4e2d...",\n    lbl_duration_sec: "\\u65f6\\u957f\\uff08\\u79d2\\uff09",\n    test_ok: "\\u6d4b\\u8bd5\\u8f6c\\u5f55\\u5b8c\\u6210",\n    test_fail: "\\u6d4b\\u8bd5\\u5f55\\u97f3\\u5931\\u8d25",\n    model_not_available: "\\u6a21\\u578b\\u672a\\u4e0b\\u8f7d\\u3002\\u8bf7\\u8fd0\\u884c: asr2clip --download-model",\n  }\n};\n\nlet currentLang = localStorage.getItem("asr2clip-lang") || "en";\nlet currentTheme = localStorage.getItem("asr2clip-theme") || "light";\n\nfunction applyTheme(theme) {\n  currentTheme = theme;\n  document.documentElement.setAttribute("data-theme", theme);\n  document.getElementById("icon-sun").style.display = theme === "light" ? "block" : "none";\n  document.getElementById("icon-moon").style.display = theme === "dark" ? "block" : "none";\n  localStorage.setItem("asr2clip-theme", theme);\n}\n\nfunction applyLang(lang) {\n  currentLang = lang;\n  const strings = I18N[lang] || I18N.en;\n  document.querySelectorAll("[data-i18n]").forEach(el => {\n    const key = el.getAttribute("data-i18n");\n    if (strings[key]) el.textContent = strings[key];\n  });\n  document.getElementById("lang-toggle").textContent = lang === "en" ? "EN" : "\\u4e2d";\n  localStorage.setItem("asr2clip-lang", lang);\n}\n\n// ===== Tabs =====\nfunction switchTab(tabName) {\n  document.querySelectorAll(".tab-btn").forEach(btn => btn.classList.toggle("active", btn.dataset.tab === tabName));\n  document.querySelectorAll(".tab-panel").forEach(p => p.classList.toggle("active", p.id === "panel-" + tabName));\n  localStorage.setItem("asr2clip-tab", tabName);\n}\n\n// ===== Init =====\ndocument.getElementById("theme-toggle").addEventListener("click", () => applyTheme(currentTheme === "light" ? "dark" : "light"));\ndocument.getElementById("lang-toggle").addEventListener("click", () => applyLang(currentLang === "en" ? "zh" : "en"));\ndocument.querySelectorAll(".tab-btn").forEach(btn => btn.addEventListener("click", () => switchTab(btn.dataset.tab)));\n\napplyTheme(currentTheme);\napplyLang(currentLang);\nconst savedTab = localStorage.getItem("asr2clip-tab");\nif (savedTab) switchTab(savedTab);\n\n// ===== Data Fetching =====\nfunction formatUptime(s) {\n  if (s < 60) return Math.round(s) + "s";\n  if (s < 3600) return Math.floor(s/60) + "m " + Math.round(s%60) + "s";\n  var h = Math.floor(s/3600); s %= 3600;\n  return h + "h " + Math.floor(s/60) + "m";\n}\n\nfunction formatDuration(s) {\n  if (s < 60) return s.toFixed(1) + "s";\n  return (s/60).toFixed(1) + "m";\n}\n\nfunction timeAgo(ts) {\n  if (!ts) return "";\n  var d = (Date.now()/1000 - ts);\n  if (d < 60) return Math.round(d) + "s ago";\n  if (d < 3600) return Math.floor(d/60) + "m ago";\n  return Math.floor(d/3600) + "h ago";\n}\n\nfunction refreshDashboard() {\n  fetch("/api/status").then(r=>r.json()).then(d=>{\n    document.getElementById("version-badge").textContent = "v" + (d.version||"?.?.?");\n    document.getElementById("status-mode").textContent = d.mode || "--";\n    document.getElementById("status-pid").textContent = d.pid || "--";\n    document.getElementById("status-uptime").textContent = formatUptime(d.uptime||0);\n    document.getElementById("status-device").textContent = d.device || "--";\n  }).catch(()=>{});\n\n  fetch("/api/stats").then(r=>r.json()).then(d=>{\n    document.getElementById("stat-count").textContent = d.transcription_count || 0;\n    document.getElementById("stat-duration").textContent = formatDuration(d.total_duration||0);\n    document.getElementById("stat-errors").textContent = d.error_count || 0;\n    var el = document.getElementById("last-text");\n    var meta = document.getElementById("last-meta");\n    if (d.last_text) {\n      el.textContent = d.last_text;\n      el.classList.remove("empty");\n      meta.textContent = timeAgo(d.last_timestamp);\n    } else {\n      el.textContent = I18N[currentLang].no_transcription;\n      el.classList.add("empty");\n      meta.textContent = "";\n    }\n  }).catch(()=>{});\n}\n\nrefreshDashboard();\nsetInterval(refreshDashboard, 3000);\n\n// ===== Toast =====\nfunction showToast(msg, type) {\n  var t = document.getElementById("toast");\n  if (!t) { t = document.createElement("div"); t.id="toast"; t.className="toast"; document.body.appendChild(t); }\n  t.textContent = msg;\n  t.className = "toast " + type + " show";\n  setTimeout(function(){ t.classList.remove("show"); }, 2500);\n}\n\n// ===== Config =====\nvar keyVisible = false;\nvar initialEngine = "openai_compat";\n\ndocument.getElementById("toggle-key-vis").addEventListener("click", function() {\n  keyVisible = !keyVisible;\n  document.getElementById("cfg-api-key").type = keyVisible ? "text" : "password";\n  document.getElementById("eye-open").style.display = keyVisible ? "none" : "block";\n  document.getElementById("eye-closed").style.display = keyVisible ? "block" : "none";\n});\n\nfunction toggleEngineFields(engine) {\n  document.getElementById("fields-openai").style.display = engine === "openai_compat" ? "block" : "none";\n  document.getElementById("fields-sherpa").style.display = engine === "sherpa_onnx" ? "block" : "none";\n  document.getElementById("engine-warn").style.display = (engine !== initialEngine) ? "flex" : "none";\n}\n\ndocument.getElementById("cfg-engine").addEventListener("change", function() {\n  toggleEngineFields(this.value);\n});\n\nfunction loadConfig() {\n  fetch("/api/config").then(r=>r.json()).then(d=>{\n    var engine = d.engine || "openai_compat";\n    initialEngine = engine;\n    document.getElementById("cfg-engine").value = engine;\n    toggleEngineFields(engine);\n    // Read from engines sub-dicts\n    var oe = (d.engines && d.engines.openai_compat) || {};\n    var se = (d.engines && d.engines.sherpa_onnx) || {};\n    // OpenAI fields\n    document.getElementById("cfg-api-url").value = oe.api_base_url || "";\n    document.getElementById("cfg-model").value = oe.model_name || "";\n    document.getElementById("cfg-api-key").value = oe.api_key || "";\n    document.getElementById("cfg-api-key").placeholder = oe.api_key ? oe.api_key : "sk-...";\n    // Sherpa fields\n    document.getElementById("cfg-sherpa-model").value = se.model_name || "";\n    document.getElementById("cfg-model-dir").value = se.model_dir || "";\n    document.getElementById("cfg-threads").value = se.num_threads || 4;\n    // General\n    document.getElementById("cfg-quiet").checked = !!d.quiet;\n    // Load model list for sherpa\n    loadModels();\n  }).catch(()=>{});\n}\n\n// ===== Model list for sherpa_onnx =====\nvar _modelData = [];\n\nfunction loadModels() {\n  fetch("/api/models").then(r=>r.json()).then(d=>{\n    _modelData = d.models || [];\n    var dl = document.getElementById("sherpa-models-list");\n    dl.innerHTML = "";\n    _modelData.forEach(function(m) {\n      var opt = document.createElement("option");\n      var suffix = m.available ? "" : " (not downloaded)";\n      if (m.is_default) suffix += " [default]";\n      opt.value = m.name;\n      opt.label = m.name + suffix;\n      dl.appendChild(opt);\n    });\n    checkModelAvailability();\n  }).catch(function(){});\n}\n\nfunction checkModelAvailability() {\n  var name = document.getElementById("cfg-sherpa-model").value.trim();\n  var warn = document.getElementById("model-warn");\n  if (!name) { warn.style.display = "none"; return; }\n  var found = _modelData.find(function(m) { return m.name === name; });\n  if (found && !found.available) {\n    warn.style.display = "block";\n  } else if (!found && _modelData.length > 0) {\n    warn.textContent = (I18N[currentLang].model_not_available || "").replace("asr2clip --download-model", "asr2clip --download-model");\n    warn.style.display = "block";\n  } else {\n    warn.style.display = "none";\n  }\n}\n\ndocument.getElementById("cfg-sherpa-model").addEventListener("input", checkModelAvailability);\n\ndocument.getElementById("btn-save-config").addEventListener("click", function() {\n  var btn = this;\n  btn.disabled = true;\n  var engine = document.getElementById("cfg-engine").value;\n  var body = { engine: engine, quiet: document.getElementById("cfg-quiet").checked, engines: {} };\n\n  // Always send the current engine\'s fields\n  if (engine === "openai_compat") {\n    var oe = {};\n    var url = document.getElementById("cfg-api-url").value.trim();\n    var model = document.getElementById("cfg-model").value.trim();\n    var key = document.getElementById("cfg-api-key").value.trim();\n    if (url) oe.api_base_url = url;\n    if (model) oe.model_name = model;\n    if (key && !key.includes("*")) oe.api_key = key;\n    body.engines.openai_compat = oe;\n  } else {\n    var se = {};\n    var smodel = document.getElementById("cfg-sherpa-model").value.trim();\n    var mdir = document.getElementById("cfg-model-dir").value.trim();\n    var threads = parseInt(document.getElementById("cfg-threads").value) || 4;\n    if (smodel) se.model_name = smodel;\n    if (mdir) se.model_dir = mdir;\n    se.num_threads = threads;\n    body.engines.sherpa_onnx = se;\n  }\n\n  fetch("/api/config", {\n    method: "POST",\n    headers: {"Content-Type": "application/json"},\n    body: JSON.stringify(body)\n  }).then(r=>r.json()).then(d=>{\n    if (d.success) {\n      showToast(I18N[currentLang].save_ok, "success");\n      loadConfig();\n    } else {\n      showToast(d.message || I18N[currentLang].save_fail, "error");\n    }\n  }).catch(()=>{\n    showToast(I18N[currentLang].save_fail, "error");\n  }).finally(()=>{ btn.disabled = false; });\n});\n\nloadConfig();\n\n// ===== Restart Engine =====\ndocument.getElementById("btn-restart-engine").addEventListener("click", function() {\n  var btn = this;\n  var lang = I18N[currentLang];\n  btn.disabled = true;\n  btn.textContent = lang.restarting;\n  fetch("/api/restart-engine", {\n    method: "POST",\n    headers: {"Content-Type": "application/json"},\n    body: "{}"\n  }).then(r=>r.json()).then(d=>{\n    if (d.success) {\n      showToast(lang.restart_ok + " (" + d.new_engine + ")", "success");\n    } else {\n      showToast(d.message || lang.restart_fail, "error");\n    }\n  }).catch(()=>{\n    showToast(lang.restart_fail, "error");\n  }).finally(()=>{\n    btn.disabled = false;\n    btn.textContent = lang.btn_restart;\n  });\n});\n\n// ===== Devices =====\nfunction loadDevices() {\n  var lang = I18N[currentLang];\n  fetch("/api/devices").then(r=>r.json()).then(d=>{\n    var list = document.getElementById("device-list");\n    if (!d.devices || d.devices.length === 0) {\n      list.innerHTML = \'<div class="device-empty">\' + (lang.no_devices) + \'</div>\';\n      return;\n    }\n    var html = "";\n    d.devices.forEach(function(dev) {\n      var cls = dev.is_active ? " active" : "";\n      var badges = "";\n      if (dev.is_default) badges += \'<span class="device-badge default">\' + lang.badge_default + \'</span>\';\n      if (dev.is_active) badges += \'<span class="device-badge current">\' + lang.badge_active + \'</span>\';\n      var btn = dev.is_active ? "" : \'<button class="btn btn-primary btn-sm" onclick="setDevice(\' + dev.index + \')">\' + lang.btn_activate + \'</button>\';\n      html += \'<div class="device-item\' + cls + \'">\'\n        + \'<div class="device-info"><div class="device-name"><span class="idx">#\' + dev.index + \'</span> \' + dev.name + \'</div>\'\n        + \'<div class="device-detail">\' + dev.channels + \' \' + lang.lbl_channels + \' &middot; \' + dev.sample_rate + \' \' + lang.lbl_hz + \'</div></div>\'\n        + \'<div class="device-badges">\' + badges + \'</div>\'\n        + btn\n        + \'</div>\';\n    });\n    list.innerHTML = html;\n  }).catch(function(){\n    document.getElementById("device-list").innerHTML = \'<div class="device-empty">\' + lang.no_devices + \'</div>\';\n  });\n}\n\nwindow.setDevice = function(idx) {\n  var lang = I18N[currentLang];\n  fetch("/api/device", {\n    method: "POST",\n    headers: {"Content-Type": "application/json"},\n    body: JSON.stringify({index: idx})\n  }).then(r=>r.json()).then(d=>{\n    if (d.success) {\n      showToast(lang.device_set_ok, "success");\n      loadDevices();\n    } else {\n      showToast(d.message || lang.device_set_fail, "error");\n    }\n  }).catch(function(){\n    showToast(lang.device_set_fail, "error");\n  });\n};\n\nloadDevices();\n\n// ===== History =====\nfunction refreshHistory() {\n  var lang = I18N[currentLang];\n  fetch("/api/history").then(r=>r.json()).then(d=>{\n    var list = document.getElementById("history-list");\n    if (!d.history || d.history.length === 0) {\n      list.innerHTML = \'<div class="history-empty">\' + lang.no_history + \'</div>\';\n      return;\n    }\n    var html = "";\n    d.history.forEach(function(h) {\n      var text = h.text || "";\n      if (text.length > 80) text = text.substring(0, 80) + "...";\n      html += \'<div class="history-item">\'\n        + \'<div class="history-text">\' + escapeHtml(text) + \'</div>\'\n        + \'<div class="history-meta"><span>\' + h.duration + \'s</span><span>\' + timeAgo(h.timestamp) + \'</span></div>\'\n        + \'</div>\';\n    });\n    list.innerHTML = html;\n  }).catch(function(){});\n}\n\nfunction escapeHtml(s) {\n  var d = document.createElement("div");\n  d.textContent = s;\n  return d.innerHTML;\n}\n\nrefreshHistory();\nsetInterval(refreshHistory, 5000);\n\n// ===== Test Record =====\ndocument.getElementById("btn-test-record").addEventListener("click", function() {\n  var btn = this;\n  var lang = I18N[currentLang];\n  var dur = parseInt(document.getElementById("test-duration").value) || 3;\n  dur = Math.max(1, Math.min(dur, 10));\n  btn.disabled = true;\n  btn.textContent = lang.recording;\n  var result = document.getElementById("test-result");\n  result.classList.remove("visible");\n\n  fetch("/api/test-record", {\n    method: "POST",\n    headers: {"Content-Type": "application/json"},\n    body: JSON.stringify({duration: dur})\n  }).then(r=>r.json()).then(d=>{\n    if (d.success) {\n      showToast(lang.test_ok, "success");\n      result.textContent = d.text || "(empty)";\n      result.classList.add("visible");\n      refreshHistory();\n    } else {\n      showToast(d.message || lang.test_fail, "error");\n    }\n  }).catch(function(){\n    showToast(lang.test_fail, "error");\n  }).finally(function(){\n    btn.disabled = false;\n    btn.textContent = lang.btn_record;\n  });\n});\n</script>\n</body>\n</html>\n'
